/*
 * Lightweight Papa-compatible CSV adapter for FinanceControll.
 * It implements the parse/unparse subset used by the local app.
 */
(function (root) {
  function parseLine(line, delimiter) {
    var cells = [];
    var cell = "";
    var quoted = false;

    for (var index = 0; index < line.length; index += 1) {
      var char = line[index];
      var next = line[index + 1];

      if (char === '"' && quoted && next === '"') {
        cell += '"';
        index += 1;
      } else if (char === '"') {
        quoted = !quoted;
      } else if (char === delimiter && !quoted) {
        cells.push(cell);
        cell = "";
      } else {
        cell += char;
      }
    }

    cells.push(cell);
    return cells;
  }

  function parse(text, options) {
    var delimiter = (options && options.delimiter) || ";";
    var header = Boolean(options && options.header);
    var skipEmptyLines = Boolean(options && options.skipEmptyLines);
    var source = String(text || "").replace(/^\uFEFF/, "");
    var lines = source.replace(/\r\n/g, "\n").replace(/\r/g, "\n").split("\n");

    if (skipEmptyLines) {
      lines = lines.filter(function (line) {
        return line.trim() !== "";
      });
    }

    if (!header) {
      return {
        data: lines.map(function (line) {
          return parseLine(line, delimiter);
        }),
        errors: []
      };
    }

    var headers = lines.length ? parseLine(lines.shift(), delimiter) : [];
    var data = lines.map(function (line) {
      var values = parseLine(line, delimiter);
      return headers.reduce(function (row, key, index) {
        row[key] = values[index] || "";
        return row;
      }, {});
    });

    return { data: data, errors: [] };
  }

  function quote(value, delimiter) {
    var text = value == null ? "" : String(value);
    if (text.indexOf('"') >= 0) {
      text = text.replace(/"/g, '""');
    }
    if (text.indexOf(delimiter) >= 0 || text.indexOf("\n") >= 0 || text.indexOf('"') >= 0) {
      return '"' + text + '"';
    }
    return text;
  }

  function unparse(input, options) {
    var delimiter = (options && options.delimiter) || ";";
    var rows = Array.isArray(input) ? input : input.data || [];
    var fields = (options && options.columns) || (input.fields || []);

    if (!fields.length && rows.length) {
      fields = Object.keys(rows[0]);
    }

    var output = [fields.map(function (field) {
      return quote(field, delimiter);
    }).join(delimiter)];

    rows.forEach(function (row) {
      output.push(fields.map(function (field) {
        return quote(row[field], delimiter);
      }).join(delimiter));
    });

    return output.join("\n");
  }

  root.Papa = { parse: parse, unparse: unparse };
})(window);
